import{_ as t,o,c as a,a2 as s}from"./chunks/framework.DTa47_fH.js";const u=JSON.parse('{"title":"PowerBI Desktop authoring guide -- swao-report.pbit","description":"","frontmatter":{},"headers":[],"relativePath":"templates/AUTHORING-GUIDE.md","filePath":"templates/AUTHORING-GUIDE.md"}'),i={name:"templates/AUTHORING-GUIDE.md"};function d(r,e,n,l,c,p){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="powerbi-desktop-authoring-guide-swao-report-pbit" tabindex="-1">PowerBI Desktop authoring guide -- <code>swao-report.pbit</code> <a class="header-anchor" href="#powerbi-desktop-authoring-guide-swao-report-pbit" aria-label="Permalink to &quot;PowerBI Desktop authoring guide -- \`swao-report.pbit\`&quot;">​</a></h1><blockquote><p><strong>This guide is for consultants who want to customise or rebuild the Power BI template.</strong> If you just want to open the template and load your assessment data, see <a href="/how-it-works#powerbi-dashboards">How it works -- PowerBI dashboards</a> instead. Your template is at <code>wsp/templates/powerbi/swao-report.pbit</code>.</p></blockquote><p>This guide walks through every step needed to author the single-app PowerBI template by hand. The end result is a <code>.pbit</code> file (template; no data embedded) that opens against any SWAO star-schema export bundle.</p><p>A separate guide covers the portfolio template: see <a href="/templates/AUTHORING-GUIDE-PORTFOLIO">Authoring guide -- portfolio</a>.</p><hr><h2 id="_0-prerequisites" tabindex="-1">0. Prerequisites <a class="header-anchor" href="#_0-prerequisites" aria-label="Permalink to &quot;0. Prerequisites&quot;">​</a></h2><ul><li>PowerBI Desktop installed (Windows). The author session below was validated against version 2.130 / 2024-04 build.</li><li>A working SWAO assessment to load. Either: <ul><li><strong>Recommended (real data):</strong> run <code>swao assess --app sovereign-health</code> then <code>swao export --app sovereign-health</code> against the canonical portfolio workspace.</li><li><strong>Synthetic:</strong> run the <code>export-star.test.ts</code> test fixture under tmp and copy the emitted <code>wsp/exports/&lt;ts&gt;/star/</code> directory somewhere durable for authoring.</li></ul></li><li>Note the absolute path to the <code>star/</code> directory; you will paste it into the parameter prompt in step 2.</li></ul><hr><h2 id="_1-open-a-blank-powerbi-desktop-file" tabindex="-1">1. Open a blank PowerBI Desktop file <a class="header-anchor" href="#_1-open-a-blank-powerbi-desktop-file" aria-label="Permalink to &quot;1. Open a blank PowerBI Desktop file&quot;">​</a></h2><p><code>File &gt; New &gt; Blank Report</code>. Save the working file as <code>swao-report-AUTHORING.pbix</code> somewhere on your machine. You will save the final result as <code>.pbit</code> (template) at the end.</p><hr><h2 id="_2-define-the-swaoexportpath-parameter" tabindex="-1">2. Define the <code>SWAOExportPath</code> parameter <a class="header-anchor" href="#_2-define-the-swaoexportpath-parameter" aria-label="Permalink to &quot;2. Define the \`SWAOExportPath\` parameter&quot;">​</a></h2><p>Templates need a parameter so the consumer can point the workbook at their own bundle.</p><ol><li><code>Home &gt; Transform Data</code> (opens Power Query Editor).</li><li><code>Manage Parameters &gt; New Parameter</code>.</li><li>Configure: <ul><li><strong>Name:</strong> <code>SWAOExportPath</code></li><li><strong>Description:</strong> &quot;Absolute path to the SWAO <code>star/</code> directory inside a <code>wsp/exports/&lt;ts&gt;/</code> bundle. Example: <code>C:\\\\my-workspace\\\\apps\\\\sovereign-health\\\\wsp\\\\exports\\\\latest\\\\star</code>.&quot;</li><li><strong>Required:</strong> yes</li><li><strong>Type:</strong> Text</li><li><strong>Suggested values:</strong> Any value</li><li><strong>Current value:</strong> the absolute path you noted in step 0.</li></ul></li><li>Click <code>OK</code>.</li></ol><hr><h2 id="_3-import-the-18-fact-dim-link-tables" tabindex="-1">3. Import the 18 fact + dim + link tables <a class="header-anchor" href="#_3-import-the-18-fact-dim-link-tables" aria-label="Permalink to &quot;3. Import the 18 fact + dim + link tables&quot;">​</a></h2><p>Each of the 18 CSV files (17 pre-v1.1.0, 18 with the v1.1.0 <code>fact_scope_coverage</code>) becomes a query in PowerBI. The column types matter for relationship detection -- numeric columns must be typed as numbers, not text.</p><h3 id="_3-1-per-csv-import-one-query-per-table" tabindex="-1">3.1 Per-CSV import (one query per table) <a class="header-anchor" href="#_3-1-per-csv-import-one-query-per-table" aria-label="Permalink to &quot;3.1 Per-CSV import (one query per table)&quot;">​</a></h3><p>We need 18 separate queries (one per fact / dim / link table), not one merged query. Note: the obvious-looking <code>Get data &gt; Folder &gt; Combine &amp; Transform Data</code> path <strong>does not</strong> create separate tables -- it merges all 18 CSVs into one table using the alphabetically-first file&#39;s schema (<code>dim_app.csv</code>), which is wrong for our star schema. Use one of the two approaches below.</p><h4 id="approach-a-manual-per-csv-reliable" tabindex="-1">Approach A -- manual per-CSV (reliable) <a class="header-anchor" href="#approach-a-manual-per-csv-reliable" aria-label="Permalink to &quot;Approach A -- manual per-CSV (reliable)&quot;">​</a></h4><p>For each of the 18 CSV files in the <code>star/</code> directory, do:</p><ol><li><code>Home &gt; Get data &gt; Text/CSV</code> (NOT Folder).</li><li>Navigate to the absolute path of the <code>star/</code> directory and pick the CSV.</li><li>In the preview dialog, click <code>OK</code>.</li><li>The query is named after the file (e.g. <code>dim_app</code>, <code>fact_signals</code>).</li></ol><p>Repeat 18 times. PowerBI&#39;s per-file CSV import auto-detects column types more reliably than the Folder source. The 18 files:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dim_app.csv                 fact_assessments.csv</span></span>
<span class="line"><span>dim_control.csv             fact_controls.csv</span></span>
<span class="line"><span>dim_evidence.csv            fact_findings.csv</span></span>
<span class="line"><span>dim_pass.csv                fact_pass_runs.csv</span></span>
<span class="line"><span>dim_regime.csv              fact_risks.csv</span></span>
<span class="line"><span>dim_severity.csv            fact_runs.csv</span></span>
<span class="line"><span>dim_wave.csv                fact_scope_coverage.csv  (v1.1.0+)</span></span>
<span class="line"><span>                            fact_signals.csv</span></span>
<span class="line"><span>                            link_control_evidence.csv</span></span>
<span class="line"><span>                            link_control_signal.csv</span></span>
<span class="line"><span>                            link_control_tag.csv      (v1.2.0+, #0361)</span></span>
<span class="line"><span>                            link_signal_evidence.csv</span></span></code></pre></div><h4 id="approach-b-m-code-paste-faster-but-more-fiddly" tabindex="-1">Approach B -- M code paste (faster but more fiddly) <a class="header-anchor" href="#approach-b-m-code-paste-faster-but-more-fiddly" aria-label="Permalink to &quot;Approach B -- M code paste (faster but more fiddly)&quot;">​</a></h4><p>In Power Query Editor, <code>Home &gt; New Source &gt; Blank Query</code> and paste:</p><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let</span></span>
<span class="line"><span>    Source = Csv.Document(File.Contents(&quot;&lt;absolute-path&gt;\\dim_app.csv&quot;),[Delimiter=&quot;,&quot;, Encoding=65001, QuoteStyle=QuoteStyle.Csv]),</span></span>
<span class="line"><span>    Headers = Table.PromoteHeaders(Source, [PromoteAllScalars=true]),</span></span>
<span class="line"><span>    Typed = Table.TransformColumnTypes(Headers, {{&quot;coverage_score&quot;, type number}, {&quot;portability_score&quot;, type number}})</span></span>
<span class="line"><span>in</span></span>
<span class="line"><span>    Typed</span></span></code></pre></div><p>Rename the query to match the table (<code>dim_app</code>). Repeat 17 times, substituting the file name and adjusting <code>TransformColumnTypes</code> per the column-types table in section 3.2.</p><h4 id="after-import" tabindex="-1">After import <a class="header-anchor" href="#after-import" aria-label="Permalink to &quot;After import&quot;">​</a></h4><p>Click <code>Home &gt; Close &amp; Apply</code>. The Daten pane should list 17 separate tables.</p><h5 id="header-row-promotion-check" tabindex="-1">Header-row promotion check <a class="header-anchor" href="#header-row-promotion-check" aria-label="Permalink to &quot;Header-row promotion check&quot;">​</a></h5><p>When PowerBI imports a CSV with mixed empty leading rows, it sometimes fails to promote the first row to headers. If any imported table shows columns named <code>Column1, Column2, ...</code> instead of the actual field names, fix it:</p><ol><li><code>Daten transformieren</code> (Power Query Editor).</li><li>Click the broken query.</li><li><code>Home &gt; Use First Row as Headers</code> (German: <code>Erste Zeile als Ueberschriften verwenden</code>).</li><li><code>Close &amp; Apply</code>.</li></ol><p>Tables observed needing this fix during the v1.0 authoring session: <code>fact_controls</code>, <code>link_control_evidence</code>, <code>link_control_signal</code>, <code>fact_risks</code>. Always check after a fresh import.</p><h3 id="_3-2-set-column-types-per-table" tabindex="-1">3.2 Set column types per table <a class="header-anchor" href="#_3-2-set-column-types-per-table" aria-label="Permalink to &quot;3.2 Set column types per table&quot;">​</a></h3><p>CRITICAL: several columns in the SWAO export contain decimal values (e.g. <code>0.93</code>, <code>0.16</code>, <code>0.875</code>). PowerBI&#39;s auto-detect frequently casts these to <strong>Whole Number</strong> (Ganze Zahl), which strips the decimal point and stores the digits as integers (<code>0.93</code> becomes <code>93</code>, <code>0.16</code> becomes <code>16</code>, <code>0.875</code> becomes <code>875</code>). Once stored as integer, the original precision cannot be recovered by changing the type. The fix must happen <strong>at the original <code>GeÃ¤nderter Typ</code> step</strong>, not as a new step appended later.</p><h4 id="decimal-columns-must-be-dezimalzahl-not-ganze-zahl" tabindex="-1">Decimal columns (must be Dezimalzahl, not Ganze Zahl) <a class="header-anchor" href="#decimal-columns-must-be-dezimalzahl-not-ganze-zahl" aria-label="Permalink to &quot;Decimal columns (must be Dezimalzahl, not Ganze Zahl)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Table</th><th>Columns</th></tr></thead><tbody><tr><td><code>fact_runs</code></td><td><code>duration_minutes</code>, <code>llm_total_cost_usd</code>, <code>lz_weight_sovereign_score</code>, <code>lz_weight_service_coverage</code>, <code>lz_weight_portability</code>, <code>lz_weight_cost_tier</code></td></tr><tr><td><code>fact_pass_runs</code></td><td><code>cost_usd</code></td></tr><tr><td><code>fact_assessments</code></td><td><code>score</code>, <code>threshold</code></td></tr><tr><td><code>dim_app</code></td><td><code>coverage_score</code>, <code>portability_score</code></td></tr><tr><td><code>dim_evidence</code></td><td><code>reliability_weight</code></td></tr></tbody></table><h4 id="whole-number-columns-ganze-zahl-is-fine" tabindex="-1">Whole-number columns (Ganze Zahl is fine) <a class="header-anchor" href="#whole-number-columns-ganze-zahl-is-fine" aria-label="Permalink to &quot;Whole-number columns (Ganze Zahl is fine)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Table</th><th>Columns</th></tr></thead><tbody><tr><td><code>fact_runs</code></td><td><code>duration_ms</code>, <code>iter</code>, <code>total_signals_emitted</code>, <code>passes_executed_count</code>, <code>llm_total_tokens_in</code>, <code>llm_total_tokens_out</code>, <code>llm_call_count</code>, <code>files_inventory_count</code>, <code>files_source_total</code>, <code>files_imports_total</code></td></tr><tr><td><code>fact_pass_runs</code></td><td><code>wall_clock_ms</code>, <code>signals_emitted</code>, <code>tokens_in</code>, <code>tokens_out</code></td></tr><tr><td><code>dim_severity</code></td><td><code>rank</code></td></tr><tr><td><code>dim_regime</code></td><td><code>controls_count</code></td></tr></tbody></table><h4 id="text-preserving-columns" tabindex="-1">Text-preserving columns <a class="header-anchor" href="#text-preserving-columns" aria-label="Permalink to &quot;Text-preserving columns&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Table</th><th>Column</th><th>Reason</th></tr></thead><tbody><tr><td><code>fact_signals</code></td><td><code>derivation_chain</code></td><td>Keep as Text -- holds semicolon-joined IDs that we do NOT want auto-split</td></tr><tr><td><code>dim_app</code></td><td><code>confidence</code></td><td>Categorical text values (low/medium/high), not a number</td></tr></tbody></table><h4 id="how-to-apply-types-reliably-avoid-the-integer-truncation-trap" tabindex="-1">How to apply types reliably (avoid the integer-truncation trap) <a class="header-anchor" href="#how-to-apply-types-reliably-avoid-the-integer-truncation-trap" aria-label="Permalink to &quot;How to apply types reliably (avoid the integer-truncation trap)&quot;">​</a></h4><p>Two safe patterns; the unsafe one is in the warning below:</p><ol><li><p><strong>Edit the original <code>GeÃ¤nderter Typ</code> step in place.</strong> In <code>Daten transformieren</code>, click a query, and in <code>Angewendete Schritte</code> (right pane) click the <strong>gear icon</strong> next to the row labeled <code>GeÃ¤nderter Typ</code> (or <code>Changed Type</code>). A dialog shows every column and its type -- change any wrong ones and click OK.</p></li><li><p><strong>Add a new step that re-casts from Text.</strong> Click the column type icon at the left of the column header. If the dropdown shows the column already as Whole Number with a wrong integer value, change it BACK to Text first (which restores the original CSV string), THEN to Decimal Number.</p></li></ol><p>Do NOT click the column-header type dropdown when the column already shows the truncated integer and pick &quot;Aktuelle ersetzen&quot; -- this looks like it edits the original step but in fact appends a new TransformColumnTypes step that casts the integer to a decimal (staying integer-valued). The original cast already happened; you need to redo it from text.</p><h3 id="_3-3-close-apply" tabindex="-1">3.3 Close &amp; Apply <a class="header-anchor" href="#_3-3-close-apply" aria-label="Permalink to &quot;3.3 Close &amp; Apply&quot;">​</a></h3><p><code>Home &gt; Close &amp; Apply</code>.</p><hr><h2 id="_4-set-relationships" tabindex="-1">4. Set relationships <a class="header-anchor" href="#_4-set-relationships" aria-label="Permalink to &quot;4. Set relationships&quot;">​</a></h2><p>Most relationships auto-detect because the foreign-key columns are named identically (<code>app_id</code>, <code>regime_id</code>, <code>pass_num</code>, <code>signal_id</code>, <code>control_id</code>, <code>evidence_id</code>, <code>severity</code>).</p><h3 id="_4-1-open-the-model-view" tabindex="-1">4.1 Open the model view <a class="header-anchor" href="#_4-1-open-the-model-view" aria-label="Permalink to &quot;4.1 Open the model view&quot;">​</a></h3><p><code>Model &gt; Manage relationships</code> (German: <code>Modell &gt; Beziehungen verwalten</code>). Most relationships auto-detect because foreign keys share column names (<code>app_id</code>, <code>regime_id</code>, <code>pass_num</code>, <code>signal_id</code>, <code>control_id</code>, <code>evidence_id</code>). Verify these required *:1 relationships exist; if any are missing, click <code>New</code> and create them:</p><table tabindex="0"><thead><tr><th>From</th><th>Column</th><th>To</th><th>Column</th></tr></thead><tbody><tr><td>fact_signals</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_signals</td><td>pass_num</td><td>dim_pass</td><td>pass_num</td></tr><tr><td>fact_controls</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_controls</td><td>regime_id</td><td>dim_regime</td><td>regime_id</td></tr><tr><td>fact_controls</td><td>control_id</td><td>dim_control</td><td>control_id</td></tr><tr><td>fact_findings</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_risks</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_assessments</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_runs</td><td>app_id</td><td>dim_app</td><td>app_id</td></tr><tr><td>fact_pass_runs</td><td>pass_num</td><td>dim_pass</td><td>pass_num</td></tr><tr><td>fact_pass_runs</td><td>run_id</td><td>fact_runs</td><td>run_id</td></tr><tr><td>link_signal_evidence</td><td>signal_id</td><td>fact_signals</td><td>signal_id</td></tr><tr><td>link_signal_evidence</td><td>evidence_id</td><td>dim_evidence</td><td>evidence_id</td></tr><tr><td>link_control_signal</td><td>control_id</td><td>fact_controls</td><td>control_id</td></tr><tr><td>link_control_signal</td><td>signal_id</td><td>fact_signals</td><td>signal_id</td></tr><tr><td>link_control_evidence</td><td>control_id</td><td>fact_controls</td><td>control_id</td></tr><tr><td>link_control_evidence</td><td>evidence_id</td><td>dim_evidence</td><td>evidence_id</td></tr><tr><td>link_control_tag</td><td>control_id</td><td>fact_controls</td><td>control_id</td></tr></tbody></table><h4 id="cycle-breaking-deactivate-fact-pass-runs-app-id-dim-app" tabindex="-1">Cycle-breaking: deactivate <code>fact_pass_runs (app_id) -&gt; dim_app</code> <a class="header-anchor" href="#cycle-breaking-deactivate-fact-pass-runs-app-id-dim-app" aria-label="Permalink to &quot;Cycle-breaking: deactivate \`fact_pass_runs (app_id) -&gt; dim_app\`&quot;">​</a></h4><p>When <code>fact_signals (pass_num) -&gt; dim_pass</code> is added, PowerBI detects an ambiguous path between <code>fact_signals</code> and <code>dim_app</code>:</p><ol><li>Direct: <code>fact_signals -&gt; dim_app</code> (via app_id).</li><li>Indirect: <code>fact_signals -&gt; dim_pass -&gt; fact_pass_runs -&gt; dim_app</code>.</li></ol><p>PowerBI refuses to activate the second relationship while both paths exist. Break the cycle by <strong>deactivating</strong> <code>fact_pass_runs (app_id) -&gt; dim_app</code>: open the relationship, uncheck <code>Diese Beziehung aktivieren</code>, save. Then activate <code>fact_signals (pass_num) -&gt; dim_pass</code>. The deactivation costs nothing for single-app dashboards (no app filter to propagate); for portfolio dashboards (multiple apps), use <code>USERELATIONSHIP()</code> in any measure that needs the fact_pass_runs / dim_app filter.</p><h4 id="skip-dim-severity-relationships-entirely" tabindex="-1">Skip dim_severity relationships entirely <a class="header-anchor" href="#skip-dim-severity-relationships-entirely" aria-label="Permalink to &quot;Skip dim_severity relationships entirely&quot;">​</a></h4><p><code>dim_severity.csv</code> is a multi-taxonomy table: rows have <code>category=severity</code> (severity levels), <code>category=control_outcome</code> (SATISFIED/PARTIAL/GAP), and <code>category=signal_outcome</code> (positive/neutral/indeterminate/negative). The <code>severity</code> column has duplicate values across categories (e.g. <code>positive</code> appears twice). PowerBI cannot create a *:1 relationship from any fact to <code>dim_severity</code> -- it forces M:N. Skipping the relationship is the right call:</p><ul><li>Visuals reference <code>fact_signals[severity]</code> directly (not <code>dim_severity[severity]</code>), which works without the relationship.</li><li>The only feature lost is sorting by <code>dim_severity[rank]</code> from a fact context. If needed, hardcode a SWITCH() in the affected measure or add a calculated column to fact tables.</li></ul><p>This is a star-schema design issue worth fixing in a future export revision (see issue tracker -- candidate for #0195: split <code>dim_severity</code> into three single-purpose dims <code>dim_severity_level</code>, <code>dim_control_outcome</code>, <code>dim_signal_outcome</code>).</p><h4 id="skip-non-existent-relationships-from-earlier-guide-versions" tabindex="-1">Skip non-existent relationships from earlier guide versions <a class="header-anchor" href="#skip-non-existent-relationships-from-earlier-guide-versions" aria-label="Permalink to &quot;Skip non-existent relationships from earlier guide versions&quot;">​</a></h4><p>The following relationships from pre-v1.1 versions of this guide <strong>do not exist in the actual schema</strong> and must be omitted:</p><table tabindex="0"><thead><tr><th>Aus</th><th>Spalte</th><th>Reason</th></tr></thead><tbody><tr><td>fact_signals</td><td>severity</td><td>dim_severity is M:N (see above)</td></tr><tr><td>fact_findings</td><td>pass_num</td><td>column does not exist in fact_findings</td></tr><tr><td>fact_findings</td><td>severity</td><td>column exists but dim_severity is M:N</td></tr><tr><td>fact_assessments</td><td>pass_num</td><td>column does not exist in fact_assessments</td></tr><tr><td>link_signal_evidence</td><td>app_id</td><td>extraneous; auto-detect adds it but link tables should join only to facts and dim_evidence per ADR-0026</td></tr></tbody></table><hr><h2 id="_5-dax-measures" tabindex="-1">5. DAX measures <a class="header-anchor" href="#_5-dax-measures" aria-label="Permalink to &quot;5. DAX measures&quot;">​</a></h2><p>Create these in a hosting table named <code>_Measures</code>. Note: <code>Measures</code> without underscore is reserved by PowerBI and rejected on creation. The leading underscore also sorts the table to the top of the Daten pane.</p><p>Create the hosting table once via <code>Modellierung &gt; Neue Tabelle</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>_Measures = ROW(&quot;Placeholder&quot;, BLANK())</span></span></code></pre></div><p>Then for each measure: right-click <code>_Measures</code> &gt; <code>Neues Measure</code>, select all in the formula bar (Strg+A), paste the measure expression, press Enter. Hide the dummy <code>Placeholder</code> column at the end via right-click &gt; <code>In Berichtsansicht ausblenden</code>.</p><p>PowerBI rejects parentheses in measure names, so <code>Average Pass Duration (s)</code> and <code>Total Run Duration (min)</code> from earlier guide versions are renamed to <code>Avg Pass Duration Sec</code> and <code>Total Run Duration Min</code> respectively.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Total Signals = COUNTROWS(&#39;fact_signals&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Negative Signals =</span></span>
<span class="line"><span>  CALCULATE([Total Signals], &#39;fact_signals&#39;[outcome] = &quot;negative&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Positive Signals =</span></span>
<span class="line"><span>  CALCULATE([Total Signals], &#39;fact_signals&#39;[outcome] = &quot;positive&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Neutral Signals =</span></span>
<span class="line"><span>  CALCULATE([Total Signals], &#39;fact_signals&#39;[outcome] = &quot;neutral&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Indeterminate Signals =</span></span>
<span class="line"><span>  CALCULATE([Total Signals], &#39;fact_signals&#39;[outcome] = &quot;indeterminate&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Rationale Coverage =</span></span>
<span class="line"><span>  DIVIDE(</span></span>
<span class="line"><span>    CALCULATE([Total Signals], LEN(&#39;fact_signals&#39;[derivation]) &gt;= 20),</span></span>
<span class="line"><span>    [Total Signals],</span></span>
<span class="line"><span>    0</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FP Consideration Rate =</span></span>
<span class="line"><span>  COALESCE(</span></span>
<span class="line"><span>    DIVIDE(</span></span>
<span class="line"><span>      CALCULATE([Total Signals], &#39;fact_signals&#39;[false_positive_considered] = &quot;true&quot;),</span></span>
<span class="line"><span>      CALCULATE([Total Signals],</span></span>
<span class="line"><span>        &#39;fact_signals&#39;[severity] IN {&quot;medium&quot;,&quot;high&quot;,&quot;critical&quot;}</span></span>
<span class="line"><span>        &amp;&amp; &#39;fact_signals&#39;[outcome] = &quot;negative&quot;),</span></span>
<span class="line"><span>      0</span></span>
<span class="line"><span>    ),</span></span>
<span class="line"><span>    0</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Controls Total = COUNTROWS(&#39;fact_controls&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Controls Satisfied =</span></span>
<span class="line"><span>  CALCULATE([Controls Total], &#39;fact_controls&#39;[status] = &quot;SATISFIED&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Controls With Gap =</span></span>
<span class="line"><span>  CALCULATE([Controls Total], &#39;fact_controls&#39;[status] = &quot;GAP&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Controls With Partial =</span></span>
<span class="line"><span>  CALCULATE([Controls Total], &#39;fact_controls&#39;[status] = &quot;PARTIAL&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Risk Score =</span></span>
<span class="line"><span>  SUMX(</span></span>
<span class="line"><span>    &#39;fact_risks&#39;,</span></span>
<span class="line"><span>    SWITCH(&#39;fact_risks&#39;[likelihood], &quot;low&quot;, 1, &quot;medium&quot;, 2, &quot;high&quot;, 3, 0) *</span></span>
<span class="line"><span>    SWITCH(&#39;fact_risks&#39;[impact], &quot;low&quot;, 1, &quot;medium&quot;, 2, &quot;high&quot;, 3, &quot;critical&quot;, 4, 0)</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total LLM Cost =</span></span>
<span class="line"><span>  COALESCE(SUM(&#39;fact_runs&#39;[llm_total_cost_usd]), 0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Avg Pass Duration Sec =</span></span>
<span class="line"><span>  AVERAGE(&#39;fact_pass_runs&#39;[wall_clock_ms]) / 1000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total Run Duration Min =</span></span>
<span class="line"><span>  SUM(&#39;fact_runs&#39;[duration_minutes])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Files Assessed =</span></span>
<span class="line"><span>  SUM(&#39;fact_runs&#39;[files_inventory_count])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Latest Assessment =</span></span>
<span class="line"><span>  MAX(&#39;fact_runs&#39;[finished_at])</span></span></code></pre></div><p>Notes:</p><ul><li>Status vs outcome on <code>fact_controls</code>: the v0.10 export populates <code>status</code> (SATISFIED / PARTIAL / GAP), not <code>outcome</code>. Earlier guide versions filtered the wrong column.</li><li><code>COALESCE(..., 0)</code> on <code>Total LLM Cost</code> and <code>FP Consideration Rate</code> ensures cards display <code>0</code> instead of <code>(Leer)</code> when stub-LLM data produces empty values.</li><li><code>Latest Assessment</code> is new in v1.1 -- use it on the Dashboard page as a &quot;data freshness&quot; indicator card.</li></ul><hr><h2 id="_6-report-pages" tabindex="-1">6. Report pages <a class="header-anchor" href="#_6-report-pages" aria-label="Permalink to &quot;6. Report pages&quot;">​</a></h2><p>Create six pages in this order. For each visual: drag the listed fields onto the indicated wells.</p><h3 id="page-1-overview-dashboard" tabindex="-1">Page 1: Overview (Dashboard) <a class="header-anchor" href="#page-1-overview-dashboard" aria-label="Permalink to &quot;Page 1: Overview (Dashboard)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Card -- 7R verdict</td><td><code>dim_app[seven_r_label]</code></td><td>Title: &quot;7R verdict&quot;</td></tr><tr><td>Card -- coverage score</td><td><code>dim_app[coverage_score]</code> (format as %)</td><td>Title: &quot;Coverage&quot;</td></tr><tr><td>Card -- latest assessment</td><td>Measure <code>[Latest Assessment]</code></td><td>Title: &quot;Last assessed at&quot; -- v1.1 freshness indicator</td></tr><tr><td>Gauge -- rationale coverage</td><td>Measure <code>[Rationale Coverage]</code></td><td>Format as %, target 0.95</td></tr><tr><td>Gauge -- FP consideration rate</td><td>Measure <code>[FP Consideration Rate]</code></td><td>Format as %, target 0.95</td></tr><tr><td>Donut -- signals by outcome</td><td>Legend: <code>fact_signals[outcome]</code>. Values: <code>[Total Signals]</code></td><td>Colour by outcome (positive=green, negative=red, neutral=grey, indeterminate=amber)</td></tr><tr><td>Bar -- top regime gaps</td><td>Axis: <code>dim_regime[regime_id]</code>. Value: <code>[Controls With Gap]</code></td><td>Use <code>regime_id</code> (not <code>name</code>); <code>name</code> is empty in v0.10 export</td></tr><tr><td>Table -- top 5 negative signals</td><td><code>fact_signals[severity]</code>, <code>[signal_id]</code>, <code>[derivation]</code></td><td>Filter: outcome = negative; sort severity desc; top 5</td></tr></tbody></table><h3 id="page-2-compliance" tabindex="-1">Page 2: Compliance <a class="header-anchor" href="#page-2-compliance" aria-label="Permalink to &quot;Page 2: Compliance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Matrix</td><td>Rows: <code>fact_controls[control_id]</code>. Columns: <code>dim_regime[regime_id]</code>. Values: <code>fact_controls[status]</code> (Erste / First)</td><td>Conditional formatting on <code>status</code>: GAP=red, PARTIAL=amber, SATISFIED=green. Conditional-formatting basis field must be a numeric measure or text column with comparable operators -- pick the field as the rule basis (not <code>risk_id</code> etc.) for <code>&gt;=</code> numeric comparisons to appear.</td></tr><tr><td>Card -- controls SATISFIED</td><td><code>[Controls Satisfied]</code></td><td></td></tr><tr><td>Card -- controls PARTIAL</td><td><code>[Controls With Partial]</code></td><td>Will display <code>--</code> when zero unless wrapped in COALESCE in the measure</td></tr><tr><td>Card -- controls GAP</td><td><code>[Controls With Gap]</code></td><td></td></tr><tr><td>Heatmap (matrix) -- cross-regime overlap</td><td>Rows: <code>fact_controls[control_id]</code>. Columns: <code>dim_regime[regime_id]</code>. Values: count(controls).</td><td>Uses <code>link_control_signal</code> join. SKIP for v0.10 fixtures -- <code>link_control_signal.csv</code> ships with 0 rows, so this visual renders empty. Document as known data gap.</td></tr><tr><td>Drill-through page target</td><td>--</td><td>Right-click a control -&gt; drill to Auditor page</td></tr></tbody></table><h3 id="page-3-signals" tabindex="-1">Page 3: Signals <a class="header-anchor" href="#page-3-signals" aria-label="Permalink to &quot;Page 3: Signals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Matrix</td><td>Rows: <code>dim_pass[name]</code>. Columns: <code>fact_signals[severity]</code>. Values: <code>[Total Signals]</code></td><td></td></tr><tr><td>Clustered column</td><td>X-axis: <code>fact_signals[severity]</code>. Legend: <code>fact_signals[outcome]</code>. Y-axis: <code>[Total Signals]</code></td><td>Replaces the &quot;Scatter&quot; from earlier guide versions -- with two categorical axes and small N, a clustered column reads better than a scatter.</td></tr><tr><td>Line chart (timeline)</td><td>X-axis: <code>dim_pass[pass_num]</code>. Y-axis: <code>[Total Signals]</code></td><td></td></tr></tbody></table><h3 id="page-4-risk" tabindex="-1">Page 4: Risk <a class="header-anchor" href="#page-4-risk" aria-label="Permalink to &quot;Page 4: Risk&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Table</td><td><code>fact_risks[risk_id]</code>, <code>[likelihood]</code>, <code>[impact]</code>, <code>[trigger]</code>, <code>[mitigation]</code></td><td>Sort by <code>[Risk Score]</code> desc</td></tr><tr><td>Bar</td><td>X: <code>fact_risks[risk_id]</code>. Y: <code>[Risk Score]</code></td><td>Conditional colour: red &gt;= 9, amber &gt;= 4, green &lt; 4</td></tr><tr><td>Donut</td><td>Legend: <code>fact_risks[category]</code>. Values: count</td><td></td></tr></tbody></table><h3 id="page-5-auditor" tabindex="-1">Page 5: Auditor <a class="header-anchor" href="#page-5-auditor" aria-label="Permalink to &quot;Page 5: Auditor&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Table -- assessments</td><td><code>fact_assessments[assessment_id]</code>, <code>[block_name]</code>, <code>[score]</code>, <code>[threshold]</code>, <code>[status]</code></td><td>Use <code>fact_assessments</code>, NOT <code>fact_controls</code>. The auditor-grade columns from earlier guide versions (<code>rationale</code>, <code>signal_refs</code>, <code>evidence_ids</code>, <code>assessor</code>, <code>assessed_at</code>, <code>remediation</code>) exist on <code>fact_controls</code> but are unpopulated in v0.10 fixtures. Update to <code>fact_controls</code> view once v0.11 enricher backfills these (#0194).</td></tr><tr><td>Slicer</td><td><code>dim_regime[regime_id]</code></td><td>Multi-select. Has limited effect on the assessments table since fact_assessments lacks regime_id; will become useful once auditor enrichment populates fact_controls.</td></tr><tr><td>Drill-through return</td><td>--</td><td>from Compliance page (deferred to v1.2 -- bookmarks + drill-through are Â§7)</td></tr></tbody></table><h3 id="page-2-update-hierarchical-compliance-matrix-v1-4-0262" tabindex="-1">Page 2 update -- Hierarchical Compliance matrix (v1.4, #0262) <a class="header-anchor" href="#page-2-update-hierarchical-compliance-matrix-v1-4-0262" aria-label="Permalink to &quot;Page 2 update -- Hierarchical Compliance matrix (v1.4, #0262)&quot;">​</a></h3><p>Replaces (or sits alongside) the flat matrix from v1.3. Auditors get a single-click path from regime to the source-code line. Operator prerequisite: bundle must be <code>bundle_schema_version: 1.1.0</code> or later (v0.0.38+ binary, includes <code>fact_scope_coverage.csv</code>).</p><h4 id="step-a-evidence-link-computed-column-on-dim-evidence" tabindex="-1">Step A -- evidence_link computed column on dim_evidence <a class="header-anchor" href="#step-a-evidence-link-computed-column-on-dim-evidence" aria-label="Permalink to &quot;Step A -- evidence_link computed column on dim_evidence&quot;">​</a></h4><p>The canonical column on <code>dim_evidence</code> is <code>source_path</code> (see <code>packages/swao/src/exports/star.ts:678</code>). Older drafts of this guide named it <code>file_path</code>; that was never correct. Some derived rows (e.g. <code>Zero files scanned</code>, <code>Analysis scope empty</code>) carry sentence strings instead of file paths; <code>file:///&lt;sentence&gt;</code> produces a dead link on click, which is the intended &quot;this is a derived signal, not a file&quot; tell. Filtering them out is a deferred enhancement.</p><p><strong>Emitter shape (post-#0267, v0.1.7+):</strong> every <code>source_path</code> value is workspace-root relative (starts with <code>wsp/</code>). Static-analysis refs land under <code>wsp/inputs/source/</code>; context-input refs (compliance, workshops, architecture docs, CMDB exports) land under <code>wsp/inputs/</code>; directory refs (<code>wsp/inputs/terraform</code>, <code>wsp/inputs/ops</code>) pass through unchanged. The previous-version operator-side conditional-prepend M-code is no longer needed; the formula below collapses to a single concat + slash normaliser.</p><ol><li><p>Power Query Editor (<code>Home &gt; Transform Data</code>).</p></li><li><p>Select query <code>dim_evidence</code>.</p></li><li><p><code>Add Column &gt; Custom Column</code>. New column name: <code>evidence_link</code>. Formula:</p><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>= EvidenceUrlPrefix &amp; Text.Replace([source_path], &quot;\\&quot;, &quot;/&quot;)</span></span></code></pre></div><p>(<code>EvidenceUrlPrefix</code> is introduced in Step B; for the first creation use <code>&quot;file:///&quot;</code> as a literal then refactor to the parameter in Step B.)</p><p><strong>Legacy bundles (pre-v0.1.7):</strong> if your bundle still emits non-normalised source_paths (file rows missing the <code>wsp/inputs/</code> prefix), use the legacy formula instead until you rebuild the bundle with v0.1.7+:</p><div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>= EvidenceUrlPrefix</span></span>
<span class="line"><span>  &amp; Text.Replace(</span></span>
<span class="line"><span>      if Text.StartsWith([source_path], &quot;wsp/&quot;)</span></span>
<span class="line"><span>        then [source_path]</span></span>
<span class="line"><span>        else &quot;wsp/inputs/&quot; &amp; [source_path],</span></span>
<span class="line"><span>      &quot;\\&quot;, &quot;/&quot;)</span></span></code></pre></div></li><li><p><code>Home &gt; Close &amp; Apply</code>.</p></li><li><p>In Report view: select the <code>dim_evidence</code> table in the Data pane, single-click <code>evidence_link</code> to select it, then ribbon <code>Spaltentools &gt; Datenkategorie &gt; Web-URL</code> (the right-click menu on the Data pane no longer carries this option in recent PBI builds).</p></li></ol><p>The <code>file:///</code> prefix points operator-laptop browsers at the local file path; once the bundle is hosted on SharePoint, change the prefix via the parameter introduced in Step B. Note: PBI Service / browsers block <code>file:///</code> navigation for security; operators on the laptop can right-click &gt; <code>Webadresse kopieren</code> and paste into Explorer as a workaround, or use Desktop where OS shell launches the file directly.</p><h4 id="step-b-evidenceurlprefix-parameter-post-publish-reconfiguration" tabindex="-1">Step B -- EvidenceUrlPrefix parameter (post-publish reconfiguration) <a class="header-anchor" href="#step-b-evidenceurlprefix-parameter-post-publish-reconfiguration" aria-label="Permalink to &quot;Step B -- EvidenceUrlPrefix parameter (post-publish reconfiguration)&quot;">​</a></h4><ol><li><code>Home &gt; Transform Data &gt; Manage Parameters &gt; New Parameter</code>.</li><li>Configure: <ul><li><strong>Name:</strong> <code>EvidenceUrlPrefix</code></li><li><strong>Description:</strong> &quot;URL prefix prepended to dim_evidence.file_path for the clickable evidence link. Defaults to <code>file:///</code> for operator laptops; reconfigure to a SharePoint or share URL after publish.&quot;</li><li><strong>Type:</strong> Text</li><li><strong>Suggested values:</strong> Any value</li><li><strong>Current value:</strong> <code>file:///</code></li></ul></li><li>Open the <code>dim_evidence</code> query and edit the <code>evidence_link</code> step to use the parameter (full formula in Step A above).</li></ol><p>For a published / SharePoint-hosted workflow, change the parameter value to the SharePoint folder URL ending in a trailing slash, e.g. <code>https://accenture.sharepoint.com/sites/swao/apps/sovereign-health/</code>. HTTPS URLs are not blocked by browsers, so clicks work in Service.</p><p>For operator-laptop authoring, the local prefix is the app workspace root, e.g. <code>file:///C:/swao-e2e/apps/sovereign-health/</code>. Use forward slashes only (backslashes break <code>file:///</code> URL parsing).</p><h4 id="step-c-master-detail-layout-on-compliance-page" tabindex="-1">Step C -- Master/detail layout on Compliance page <a class="header-anchor" href="#step-c-master-detail-layout-on-compliance-page" aria-label="Permalink to &quot;Step C -- Master/detail layout on Compliance page&quot;">​</a></h4><p><strong>Why not a single hierarchical matrix:</strong> the v1.4 draft had <code>dim_evidence[evidence_link]</code> as the leaf row level under <code>fact_signals[signal_id]</code>. With the M:M bridges that join <code>fact_controls -&gt; link_control_signal -&gt; fact_signals -&gt; link_signal_evidence -&gt; dim_evidence</code>, PBI raises <code>InvalidUnconstrainedJoin</code> because it cannot pick an unambiguous join path between the four tables in a single visual. The fix is a <strong>master/detail pattern</strong>: the matrix carries the drill-down to signal level; a separate Tabelle visual on the same page shows the evidence rows for whatever the auditor has selected in the matrix. PBI&#39;s auto cross-filter between the two visuals delivers the same UX as the single-matrix design without the join error.</p><h5 id="c-0-import-link-control-signal-if-the-pbix-predates-it" tabindex="-1">C.0 -- import <code>link_control_signal</code> if the .pbix predates it <a class="header-anchor" href="#c-0-import-link-control-signal-if-the-pbix-predates-it" aria-label="Permalink to &quot;C.0 -- import \`link_control_signal\` if the .pbix predates it&quot;">​</a></h5><p>The bundle has shipped <code>link_control_signal.csv</code> since v0.0.36, but existing .pbix files authored before then will not auto-import it on refresh. Same pattern as <code>fact_scope_coverage</code> -- one Power Query expression per table.</p><ol><li><code>Start &gt; Daten transformieren &gt; Neue Quelle &gt; Text/CSV</code>.</li><li>Navigate to <code>&lt;SWAOExportPath&gt;\\link_control_signal.csv</code>. OK.</li><li>Verify headers promoted (<code>control_id, signal_id, regime_id, app_id</code>).</li><li>Rewire the <code>Quelle</code> step to use <code>SWAOExportPath</code> (mirror the shape of any existing fact_* query).</li><li><code>SchlieÃŸen &amp; Ã¼bernehmen</code>.</li></ol><h5 id="c-1-relationships-required-by-the-master-detail-wiring" tabindex="-1">C.1 -- relationships required by the master/detail wiring <a class="header-anchor" href="#c-1-relationships-required-by-the-master-detail-wiring" aria-label="Permalink to &quot;C.1 -- relationships required by the master/detail wiring&quot;">​</a></h5><p>In <code>Modellansicht &gt; Beziehungen verwalten</code>, ensure these five relationships exist and have the listed cardinality + cross-filter direction + active state. PBI will raise the ambiguity guard on the M:M edges; the guard is the reason for the M:M cardinality (M:M treats the relationship as &quot;limited&quot; and bypasses the strict constraint check that M:1 enforces).</p><table tabindex="0"><thead><tr><th>From</th><th>To</th><th>KardinalitÃ¤t</th><th>Kreuzfilter</th><th>Aktiv</th></tr></thead><tbody><tr><td><code>dim_regime[regime_id]</code></td><td><code>fact_controls[regime_id]</code></td><td><code>*:1</code></td><td>Einfach</td><td>yes</td></tr><tr><td><code>link_control_signal[control_id]</code></td><td><code>fact_controls[control_id]</code></td><td><code>*:1</code></td><td>Einfach</td><td>yes</td></tr><tr><td><code>link_control_signal[signal_id]</code></td><td><code>fact_signals[signal_id]</code></td><td><code>*:*</code></td><td>Einfach</td><td>yes</td></tr><tr><td><code>link_signal_evidence[signal_id]</code></td><td><code>fact_signals[signal_id]</code></td><td><code>*:*</code></td><td>Einfach</td><td>yes (v1.3 had this Inaktiv; activate it)</td></tr><tr><td><code>link_signal_evidence[evidence_id]</code></td><td><code>dim_evidence[evidence_id]</code></td><td><code>*:1</code></td><td><strong>Beide</strong></td><td>yes (bidirectional cross-filter required so signal context flows down to evidence)</td></tr></tbody></table><p>The pre-existing <code>link_signal_evidence[app_id] -&gt; dim_app[app_id]</code> stays Aktiv as-is.</p><h5 id="c-2-matrix-visual-compliance-status-by-regime-drill-down" tabindex="-1">C.2 -- matrix visual: Compliance Status by Regime (drill down) <a class="header-anchor" href="#c-2-matrix-visual-compliance-status-by-regime-drill-down" aria-label="Permalink to &quot;C.2 -- matrix visual: Compliance Status by Regime (drill down)&quot;">​</a></h5><ol><li>Insert Matrix visual.</li><li><strong>Zeilen</strong> (top to bottom): <ul><li><code>dim_regime[regime_id]</code></li><li><code>fact_controls[control_id]</code></li><li><code>fact_signals[signal_id]</code></li></ul></li><li><strong>Werte</strong>: <ul><li><code>fact_controls[status]</code> (aggregation <code>Erste</code> -- the recent PBI builds dropped the &quot;Don&#39;t summarise&quot; wording for text columns; <code>Erste</code> is the equivalent because each control_id row has exactly one status). Rename for visual: <code>FÃ¼r dieses Visual umbenennen -&gt; &quot;Status&quot;</code>.</li><li><code>fact_signals[severity]</code> (aggregation <code>Erste</code>, rename to <code>&quot;Severity&quot;</code>).</li></ul></li><li><strong>Format &gt; Zeilenheader &gt; +/- Symbole</strong> = An (so each row gets a click-to-expand affordance).</li><li><strong>Titel</strong> = <code>&quot;Compliance Status by Regime (drill down)&quot;</code>, left-aligned, 14-16pt.</li></ol><h5 id="c-3-evidence-tabelle-supporting-evidence" tabindex="-1">C.3 -- evidence Tabelle: Supporting Evidence <a class="header-anchor" href="#c-3-evidence-tabelle-supporting-evidence" aria-label="Permalink to &quot;C.3 -- evidence Tabelle: Supporting Evidence&quot;">​</a></h5><ol><li>Insert Tabelle visual on the same page (right of the matrix or below, depending on layout).</li><li><strong>Spalten</strong> in order: <ul><li><code>dim_evidence[evidence_id]</code></li><li><code>dim_evidence[evidence_link]</code></li><li><code>dim_evidence[evidence_type]</code></li><li><code>dim_evidence[source_path]</code></li><li><code>dim_evidence[reliability_weight]</code></li></ul></li><li><strong>Titel</strong> = <code>&quot;Supporting Evidence&quot;</code>.</li></ol><h5 id="c-4-severity-slicer-compact-coloured" tabindex="-1">C.4 -- severity slicer (compact, coloured) <a class="header-anchor" href="#c-4-severity-slicer-compact-coloured" aria-label="Permalink to &quot;C.4 -- severity slicer (compact, coloured)&quot;">​</a></h5><ol><li>Insert Datenschnitt (slicer).</li><li><strong>Feld</strong> = <code>fact_signals[severity]</code> (NOT <code>fact_controls[severity]</code> -- the control table only carries the control-level subset of severity values; the signal table carries the full lattice including <code>low</code>, <code>informational</code>, <code>positive</code>).</li><li><strong>Format &gt; Layout mit mehreren SchaltflÃ¤chen &gt; Orientierung</strong> = Horizontal; <strong>Spalten</strong> = 6; <strong>Innenabstand</strong> = 6 px; <strong>Schriftgrad</strong> = 10 pt. All six tiles fit one row.</li><li><strong>Format &gt; Slicer-Einstellungen &gt; Auswahl &gt; Option &quot;Alles auswÃ¤hlen&quot; anzeigen</strong> = Aus (the slicer&#39;s eraser icon already provides one-click reset).</li><li>Apply CF on <code>SchaltflÃ¤chen &gt; Hintergrund</code> in all three states (<code>Standard</code>, <code>Bei Auswahl</code>, <code>Beim Hover</code>): <ul><li><code>critical</code> -&gt; <code>#C62828</code></li><li><code>high</code> -&gt; <code>#EF6C00</code></li><li><code>medium</code> -&gt; <code>#F9A825</code></li><li><code>low</code> -&gt; <code>#9CCC65</code></li><li><code>informational</code> -&gt; <code>#9E9E9E</code></li><li><code>positive</code> -&gt; <code>#2E7D32</code></li></ul></li><li>Apply CF on <code>SchaltflÃ¤chen &gt; Text &gt; Schriftfarbe</code> to <code>#FFFFFF</code> (white) for all three states. Optionally split into <code>#212121</code> black on the lighter tiles (<code>medium</code>, <code>low</code>) for tighter contrast.</li></ol><h5 id="c-5-visual-interactions" tabindex="-1">C.5 -- visual interactions <a class="header-anchor" href="#c-5-visual-interactions" aria-label="Permalink to &quot;C.5 -- visual interactions&quot;">​</a></h5><p>The slicer must NOT be cross-filtered by the matrix or the evidence Tabelle, otherwise its tile list will narrow to only the severities present in the current selection.</p><p>For each of <code>matrix</code> and <code>evidence Tabelle</code>:</p><ol><li>Click the visual.</li><li>Ribbon <code>Format &gt; Interaktionen bearbeiten</code>.</li><li>On the slicer (small icons appear in its top-right when edit mode is active), click the <strong>circle-with-line</strong> icon (Keine Auswirkung).</li><li>Toggle <code>Interaktionen bearbeiten</code> off.</li></ol><p>The default matrix -&gt; evidence Tabelle interaction stays as filter (no change needed) -- that is what powers the cross-filter UX.</p><h5 id="c-6-kpi-cards-optional-polish" tabindex="-1">C.6 -- KPI cards (optional polish) <a class="header-anchor" href="#c-6-kpi-cards-optional-polish" aria-label="Permalink to &quot;C.6 -- KPI cards (optional polish)&quot;">​</a></h5><p>If three top-page KPI cards (<code>Controls Satisfied / With Partial / With Gap</code>) are present from the v1.3 baseline:</p><ol><li>Make each card narrower so the label wraps to two lines, or enable <code>Format &gt; Beschriftung &gt; Wortumbruch</code>. If Wortumbruch is not in your build, rename the measure with a Shift+Enter line break in the Werte well: <code>Controls\\nSatisfied</code>.</li><li>Optionally apply CF on the card value to inherit the same red/ amber/green palette as the matrix Status column.</li></ol><h4 id="step-d-conditional-formatting-on-status-matrix" tabindex="-1">Step D -- Conditional formatting on Status (matrix) <a class="header-anchor" href="#step-d-conditional-formatting-on-status-matrix" aria-label="Permalink to &quot;Step D -- Conditional formatting on Status (matrix)&quot;">​</a></h4><p>The matrix Status column (renamed in C.2) carries the traffic-light CF that makes the dashboard scannable.</p><ol><li>Matrix selected. In Werte, click the dropdown on <code>Status</code> -&gt; <code>Bedingte Formatierung &gt; Hintergrundfarbe</code>.</li><li><strong>Formatierungsstil</strong> = <code>Regeln</code>. Field = <code>Status</code> (Erste).</li><li>Rules (text equality on <code>status</code>): <ul><li><code>GAP</code> -&gt; <code>#C62828</code> (red)</li><li><code>PARTIAL</code> -&gt; <code>#F9A825</code> (amber)</li><li><code>SATISFIED</code> -&gt; <code>#2E7D32</code> (green)</li><li><code>UNKNOWN</code> -&gt; <code>#9E9E9E</code> (grey)</li><li><code>N_A</code> -&gt; <code>#E0E0E0</code> (light grey)</li></ul></li><li>Apply the same CF on <code>Status &gt; Bedingte Formatierung &gt; Schriftfarbe</code> with one rule: when value is not empty -&gt; <code>#FFFFFF</code> (white). Keeps text readable against every status colour.</li></ol><p>Apply the same approach on the Severity column (matrix Werte) using the palette from C.4 step 5.</p><h4 id="step-e-mirror-the-master-detail-pattern-on-auditor-signals-pages" tabindex="-1">Step E -- Mirror the master/detail pattern on Auditor + Signals pages <a class="header-anchor" href="#step-e-mirror-the-master-detail-pattern-on-auditor-signals-pages" aria-label="Permalink to &quot;Step E -- Mirror the master/detail pattern on Auditor + Signals pages&quot;">​</a></h4><ul><li><strong>Auditor page (Page 5):</strong> add the same matrix + evidence Tabelle pair below the existing audit summary. Drill-down stays on one page; auditor clicks a signal in the matrix to load supporting artefacts in the Tabelle.</li><li><strong>Signals page (Page 3):</strong> matrix rows <code>dim_pass[name] -&gt; fact_signals[signal_id]</code>; evidence Tabelle as in C.3. Severity CF on the signal row.</li></ul><p>The same relationship + interaction rules from C.1 + C.5 apply.</p><h4 id="step-f-smoke" tabindex="-1">Step F -- Smoke <a class="header-anchor" href="#step-f-smoke" aria-label="Permalink to &quot;Step F -- Smoke&quot;">​</a></h4><p>After save:</p><ol><li>Click <code>+</code> on a regime row in the matrix (e.g. <code>GDPR</code>); expands to contributing controls with their Status colour.</li><li>Click <code>+</code> on a red <code>GDPR_Art_9</code> row; expands to the contributing signal_ids with their Severity colour (e.g. <code>DATA-01</code> informational).</li><li><strong>Click the signal_id row</strong> (e.g. <code>DATA-01</code>). The evidence Tabelle on the right/below narrows to the artefacts cited by that signal.</li><li>Right-click an <code>evidence_link</code> cell &gt; <code>Webadresse kopieren</code> and paste into Windows Explorer (or single-click in PBI Desktop if the OS has a registered handler for the file extension). The source file opens.</li><li>Click <code>critical</code> in the severity slicer. The matrix narrows to controls/signals at critical severity. The evidence Tabelle narrows accordingly. Click the slicer&#39;s eraser icon to reset.</li></ol><h4 id="step-g-dashboard-page-rag-palette-swao-header" tabindex="-1">Step G -- Dashboard page RAG palette + SWAO header <a class="header-anchor" href="#step-g-dashboard-page-rag-palette-swao-header" aria-label="Permalink to &quot;Step G -- Dashboard page RAG palette + SWAO header&quot;">​</a></h4><p>The Dashboard page is the executive summary view, so it benefits from consistent traffic-light colour across every visual. Six small CF applications cover it.</p><h5 id="g-1-donut-total-signals-nach-outcome" tabindex="-1">G.1 -- donut &quot;Total Signals nach outcome&quot; <a class="header-anchor" href="#g-1-donut-total-signals-nach-outcome" aria-label="Permalink to &quot;G.1 -- donut &quot;Total Signals nach outcome&quot;&quot;">​</a></h5><p>Map outcome categories to RAG (<code>Format &gt; Slices &gt; Farben</code> -&gt; per-value constant colour for each outcome):</p><ul><li><code>negative</code> -&gt; <code>#C62828</code> (red)</li><li><code>indeterminate</code> -&gt; <code>#F9A825</code> (amber)</li><li><code>neutral</code> -&gt; <code>#9E9E9E</code> (grey)</li><li><code>positive</code> -&gt; <code>#2E7D32</code> (green)</li></ul><h5 id="g-2-bar-chart-controls-with-gap-nach-regime-id" tabindex="-1">G.2 -- bar chart &quot;Controls With Gap nach Regime ID&quot; <a class="header-anchor" href="#g-2-bar-chart-controls-with-gap-nach-regime-id" aria-label="Permalink to &quot;G.2 -- bar chart &quot;Controls With Gap nach Regime ID&quot;&quot;">​</a></h5><p>Format &gt; <code>Farbe &gt; fx</code> -&gt; rules on the <code>Controls With Gap</code> measure (unit <code>Zahl</code>, not <code>Prozent</code>):</p><ul><li><code>&gt;= 3</code> -&gt; red <code>#C62828</code></li><li><code>&gt;= 1 und &lt; 3</code> -&gt; amber <code>#F9A825</code></li><li><code>= 0</code> -&gt; green <code>#2E7D32</code></li></ul><h5 id="g-3-replatform-coverage-card" tabindex="-1">G.3 -- Replatform Coverage % card <a class="header-anchor" href="#g-3-replatform-coverage-card" aria-label="Permalink to &quot;G.3 -- Replatform Coverage % card&quot;">​</a></h5><p>Format &gt; <code>Werte &gt; Schriftfarbe &gt; fx</code> -&gt; rules on the coverage measure:</p><ul><li><code>&gt;= 90%</code> -&gt; green</li><li><code>70% - 89%</code> -&gt; amber</li><li><code>&lt; 70%</code> -&gt; red</li></ul><h5 id="g-4-rationale-coverage-gauge-scale-0-2-00" tabindex="-1">G.4 -- Rationale Coverage gauge (scale 0 - 2.00) <a class="header-anchor" href="#g-4-rationale-coverage-gauge-scale-0-2-00" aria-label="Permalink to &quot;G.4 -- Rationale Coverage gauge (scale 0 - 2.00)&quot;">​</a></h5><p>PBI gauge fill colour supports CF via <code>Format &gt; Farben &gt; FÃ¼llfarbe &gt; fx</code>. Rules on the <code>Rationale Coverage</code> measure (unit <code>Zahl</code>):</p><ul><li><code>&gt;= 0 und &lt; 0.80</code> -&gt; red</li><li><code>&gt;= 0.80 und &lt; 1.60</code> -&gt; amber</li><li><code>&gt;= 1.60 und &lt;= 2</code> -&gt; green</li></ul><p>Also set <code>Format &gt; Messachse</code>:</p><ul><li><strong>Min</strong> = <code>0</code></li><li><strong>Max</strong> = <code>2</code></li><li><strong>Ziel</strong> (Target) = <code>1.60</code> (the 80% target line)</li></ul><p><code>Zielfarbe</code> (target line colour) stays constant <code>#424242</code> (dark grey) for contrast against any fill colour.</p><h5 id="g-5-fp-consideration-rate-gauge-scale-0-0-73" tabindex="-1">G.5 -- FP Consideration Rate gauge (scale 0 - 0.73) <a class="header-anchor" href="#g-5-fp-consideration-rate-gauge-scale-0-0-73" aria-label="Permalink to &quot;G.5 -- FP Consideration Rate gauge (scale 0 - 0.73)&quot;">​</a></h5><p>Same approach, thresholds proportional:</p><ul><li><code>&gt;= 0 und &lt; 0.30</code> -&gt; red</li><li><code>&gt;= 0.30 und &lt; 0.60</code> -&gt; amber</li><li><code>&gt;= 0.60 und &lt;= 0.73</code> -&gt; green</li></ul><p>Messachse: Min <code>0</code>, Max <code>0.73</code>, Ziel <code>0.70</code>.</p><h5 id="g-6-severity-column-on-the-signal-table" tabindex="-1">G.6 -- severity column on the signal table <a class="header-anchor" href="#g-6-severity-column-on-the-signal-table" aria-label="Permalink to &quot;G.6 -- severity column on the signal table&quot;">​</a></h5><p>Same palette as Compliance / Auditor / Signals -- apply via Werte dropdown on <code>severity</code> -&gt; <code>Bedingte Formatierung &gt; Hintergrundfarbe</code>, plus white font colour for readability:</p><ul><li><code>critical</code> -&gt; <code>#C62828</code></li><li><code>high</code> -&gt; <code>#EF6C00</code></li><li><code>medium</code> -&gt; <code>#F9A825</code></li><li><code>low</code> -&gt; <code>#9CCC65</code></li><li><code>informational</code> -&gt; <code>#9E9E9E</code></li><li><code>positive</code> -&gt; <code>#2E7D32</code></li></ul><h5 id="g-7-swao-branded-header" tabindex="-1">G.7 -- SWAO branded header <a class="header-anchor" href="#g-7-swao-branded-header" aria-label="Permalink to &quot;G.7 -- SWAO branded header&quot;">​</a></h5><p>Top of the Dashboard page, full canvas width, ~140 px tall. Two elements side by side:</p><ol><li><strong>Logo (left)</strong>: <code>EinfÃ¼gen &gt; Bild</code> -&gt; SWAO hexagon-S file from <code>swao/docs/assets/</code> (or <code>swao-premium/assets/</code>). ~80 x 80 px.</li><li><strong>Text block (right)</strong> -- four-line layout: <ul><li>Line 1: <code>SWAO -- Sovereign Workload Assessment &amp; Onboarding</code> (18-20 pt bold, brand purple <code>#5C2D91</code>).</li><li>Line 2: <code>Built with AI. Runs on AI. Defensible to auditors.</code> (11 pt italic, <code>#212121</code> or <code>#5C2D91</code> lighter shade).</li><li>Line 3: <code>Accenture x meshcloud | Internal, Confidential | v&lt;binary version&gt;</code> (9 pt regular, grey <code>#616161</code>).</li><li>Line 4: <code>Contacts: &lt;name1&gt; (&lt;email1&gt;) | &lt;name2&gt; (&lt;email2&gt;)</code> plus optional Documentation URL on a separate row (9 pt regular, grey). Email addresses should be set as <code>mailto:</code> hyperlinks via the Textfeld toolbar &gt; Link einfÃ¼gen.</li></ul></li></ol><p>Bump the binary version on Line 3 whenever shipping a new .pbit revision so operators can confirm template freshness at a glance.</p><h4 id="step-h-link-control-tag-tag-slicer-v1-2-0-bundle-0361" tabindex="-1">Step H -- link_control_tag tag slicer (v1.2.0+ bundle, #0361) <a class="header-anchor" href="#step-h-link-control-tag-tag-slicer-v1-2-0-bundle-0361" aria-label="Permalink to &quot;Step H -- link_control_tag tag slicer (v1.2.0+ bundle, #0361)&quot;">​</a></h4><p>Bundle prerequisite: <code>link_control_tag.csv</code> present at <code>star/link_control_tag.csv</code> (v0.1.7+ binary, bundle_schema_version <code>1.2.0</code>). One row per (control, tag) pair; columns: <code>control_id, tag, tag_kind, regime_id, app_id</code>.</p><p>Use case: filter Compliance / Auditor pages by a tag axis so the operator can show only &quot;technical&quot; controls, or only &quot;applies-to.processor&quot; controls, during a client walkthrough of #0348 taxonomy.</p><ol><li>Power Query Editor &gt; add the new <code>link_control_tag</code> table as a query (Approach A from Â§3.1; same shape as the other link tables -- single-row-of-headers CSV with one column-types pass).</li><li>Model view &gt; add relationships: <ul><li><code>link_control_tag[control_id]</code> -&gt; <code>fact_controls[control_id]</code> (M:M; cross-filter direction <code>Beide</code>).</li></ul></li><li>On Compliance page (or wherever the tag filter is useful), add a Datenschnitt over <code>link_control_tag[tag]</code> (or <code>[tag_kind]</code> for a coarser axis-vs-applies-to filter).</li><li>Style: list-style slicer with two-column layout works well for the ~40 distinct tag values across the 4 currently-tagged frameworks (GDPR, NIST CSF 2.0, HIPAA, PCI DSS).</li></ol><p>Note: the slicer filters <code>fact_controls</code> through the M:M bridge. Controls without tags (community frameworks not yet backfilled) will filter OUT when any tag is selected -- this is the intended behaviour (&quot;show me only controls in this tag bucket&quot;). Use a <code>(All)</code> button on the slicer to clear the filter and bring untagged controls back.</p><p><code>tag_kind</code> values: <code>axis</code> (per-framework <code>axis.value</code> form like <code>technical-vs-organisational.technical</code>) or <code>applies-to</code> (universal <code>applies-to.processor</code> / <code>applies-to.controller</code> / etc.).</p><hr><h3 id="page-7-scope-coverage-v1-5-0263-phase-3" tabindex="-1">Page 7: Scope Coverage (v1.5, #0263 Phase 3) <a class="header-anchor" href="#page-7-scope-coverage-v1-5-0263-phase-3" aria-label="Permalink to &quot;Page 7: Scope Coverage (v1.5, #0263 Phase 3)&quot;">​</a></h3><p>New page surfacing Pass 13 Scope Coverage output. Bundle prerequisite: <code>fact_scope_coverage.csv</code> present + <code>fact_assessments</code> row with <code>block_name = &#39;scope_coverage&#39;</code> (v0.0.38+ binary, #0265).</p><h4 id="step-0-important-add-fact-scope-coverage-as-a-new-power-query" tabindex="-1">Step 0 -- IMPORTANT: add fact_scope_coverage as a new Power Query <a class="header-anchor" href="#step-0-important-add-fact-scope-coverage-as-a-new-power-query" aria-label="Permalink to &quot;Step 0 -- IMPORTANT: add fact_scope_coverage as a new Power Query&quot;">​</a></h4><p>When upgrading an existing v1.3 .pbix to v1.5, refreshing against a v1.1.0 bundle does <strong>not</strong> auto-import the new CSV. Power Query has one expression per table; you must add an 18th query for the new <code>fact_scope_coverage.csv</code>.</p><ol><li><code>Home &gt; Transform Data</code> (Power Query Editor).</li><li><code>Home &gt; New Source &gt; Text/CSV</code>.</li><li>Navigate to <code>&lt;SWAOExportPath&gt;\\fact_scope_coverage.csv</code> and pick it.</li><li>In the preview, click <code>OK</code>. The query lands named <code>fact_scope_coverage</code>.</li><li>Verify the first row promoted to headers (<code>blind_spot_id, app_id, name, category, coverage, severity, input_required, input_provided, related_regimes, assessor, assessed_at</code>). If not, <code>Home &gt; Use First Row as Headers</code>.</li><li>All columns stay as <strong>Text</strong> -- no decimal/integer types in this table.</li><li><strong>Rewire to the <code>SWAOExportPath</code> parameter.</strong> Click the <code>Quelle</code> (Source) step. Edit the formula bar from a hard-coded path to:<div class="language-m vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">m</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>= Csv.Document(File.Contents(SWAOExportPath &amp; &quot;\\fact_scope_coverage.csv&quot;),</span></span>
<span class="line"><span>               [Delimiter=&quot;,&quot;, Encoding=65001, QuoteStyle=QuoteStyle.Csv])</span></span></code></pre></div>Compare against any other fact_* query for the exact argument shape your environment uses.</li><li><code>Home &gt; Close &amp; Apply</code>. <code>fact_scope_coverage</code> appears in the Data pane.</li></ol><p>For first-time authoring (fresh .pbix), this query is one of the 18 imports from Â§3.1 -- no extra step needed.</p><h4 id="step-a-coverage-ratio-card" tabindex="-1">Step A -- Coverage ratio card <a class="header-anchor" href="#step-a-coverage-ratio-card" aria-label="Permalink to &quot;Step A -- Coverage ratio card&quot;">​</a></h4><ol><li>Insert Card visual.</li><li>Fields well: drag a measure <code>[Scope Coverage Ratio] = CALCULATE(SELECTEDVALUE(fact_assessments[score]), fact_assessments[block_name] = &quot;scope_coverage&quot;)</code>.</li><li>Format <code>[Scope Coverage Ratio]</code> as Percentage with 1 decimal.</li><li>Title: &quot;Scope coverage ratio&quot;.</li></ol><h4 id="step-b-donut-closed-partial-open" tabindex="-1">Step B -- Donut: closed / partial / open <a class="header-anchor" href="#step-b-donut-closed-partial-open" aria-label="Permalink to &quot;Step B -- Donut: closed / partial / open&quot;">​</a></h4><ol><li>Insert Donut chart visual.</li><li>Legend: <code>fact_scope_coverage[coverage]</code>.</li><li>Values: <code>[Total Scope Entries] = COUNTROWS(fact_scope_coverage)</code>.</li><li>Apply colour rules: closed=green (<code>#2E7D32</code>), partial=amber (<code>#F9A825</code>), open=red (<code>#C62828</code>).</li><li>Title: &quot;Scope coverage breakdown&quot;.</li></ol><h4 id="step-c-hierarchical-matrix-category-blind-spot-id-related-regimes" tabindex="-1">Step C -- Hierarchical matrix: category -&gt; blind_spot_id -&gt; related_regimes <a class="header-anchor" href="#step-c-hierarchical-matrix-category-blind-spot-id-related-regimes" aria-label="Permalink to &quot;Step C -- Hierarchical matrix: category -&gt; blind_spot_id -&gt; related_regimes&quot;">​</a></h4><p>Reuses the same Matrix-with-row-hierarchy pattern from Â§6.7 above.</p><table tabindex="0"><thead><tr><th>Position</th><th>Field</th></tr></thead><tbody><tr><td>Top</td><td><code>fact_scope_coverage[category]</code></td></tr><tr><td>Mid</td><td><code>fact_scope_coverage[blind_spot_id]</code></td></tr><tr><td>Leaf</td><td><code>fact_scope_coverage[related_regimes]</code> (semicolon-joined; consider splitting in Power Query for true list)</td></tr></tbody></table><ul><li><strong>Values well:</strong> <code>fact_scope_coverage[coverage]</code>.</li><li><strong>Conditional formatting</strong> on the coverage cell using the same rules as Step B (closed/partial/open colour palette).</li><li><strong>Page slicer</strong> on <code>dim_app[app_id]</code> so the operator can focus per-app.</li></ul><h4 id="step-d-open-spots-table" tabindex="-1">Step D -- Open-spots table <a class="header-anchor" href="#step-d-open-spots-table" aria-label="Permalink to &quot;Step D -- Open-spots table&quot;">​</a></h4><p>Insert Table visual.</p><ul><li><strong>Columns:</strong> <code>blind_spot_id</code>, <code>name</code>, <code>severity</code>, <code>category</code>, <code>input_required</code>, <code>related_regimes</code>.</li><li><strong>Visual-level filter:</strong> <code>coverage</code> is <code>open</code>.</li><li><strong>Sort:</strong> <code>severity</code> desc (custom order: <code>critical &gt; high &gt; medium &gt; low &gt; informational</code>). Use a measure or a computed column for the sort if PowerBI defaults to alphabetical.</li><li><strong>Title:</strong> &quot;Open blind spots -- inputs to request from the customer&quot;.</li></ul><p>This is the consultant&#39;s call-list. Each row is one artefact to ask the customer for at the next workshop.</p><h4 id="step-e-smoke" tabindex="-1">Step E -- Smoke <a class="header-anchor" href="#step-e-smoke" aria-label="Permalink to &quot;Step E -- Smoke&quot;">​</a></h4><ol><li>Open .pbit against the v0.0.38+ bundle.</li><li>Card shows coverage ratio (e.g. 0.40 = 40%).</li><li>Donut shows the closed / partial / open split with the right colours.</li><li>Matrix expands <code>process</code> -&gt; <code>BS_NETWORK_POLICY</code> -&gt; <code>BSI_C5; ISO27001</code>.</li><li>Open-spots table lists the blind spots sorted by severity, with the <code>input_required</code> path the consultant should ask for.</li></ol><hr><h3 id="page-6-run-stats" tabindex="-1">Page 6: Run Stats <a class="header-anchor" href="#page-6-run-stats" aria-label="Permalink to &quot;Page 6: Run Stats&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visual</th><th>Fields</th><th>Notes</th></tr></thead><tbody><tr><td>Card</td><td>Measure <code>[Total Run Duration Min]</code></td><td>Title: &quot;Duration (min)&quot;</td></tr><tr><td>Card</td><td>Measure <code>[Total LLM Cost]</code></td><td>Title: &quot;LLM cost (USD)&quot; -- format $ #,##0.000</td></tr><tr><td>Card</td><td>Measure <code>[Files Assessed]</code></td><td>Title: &quot;Files assessed&quot;</td></tr><tr><td>Card</td><td>Measure <code>[Avg Pass Duration Sec]</code></td><td>Title: &quot;Avg pass duration (s)&quot;</td></tr><tr><td>Stacked column</td><td>X-axis: <code>fact_pass_runs[pass_name]</code>. Y-axis: <code>fact_pass_runs[wall_clock_ms]</code> (Sum)</td><td>Title: &quot;Per-pass wall-clock (ms)&quot;. Use <strong>Stacked Column</strong> (Gestapeltes SÃ¤ulendiagramm), NOT 100% Stacked Column -- the latter forces every bar to fill 100% of the height because there is only one series.</td></tr><tr><td>(skip) Stacked tokens bar</td><td>--</td><td>All token columns are blank in stub-LLM data; renders empty. Skip. Add when running against real LLM provider.</td></tr><tr><td>(skip) Multi-run trend line</td><td>--</td><td>Only 1 run in <code>fact_runs</code> for single-app dashboards on v0.10. Skip. Add once multiple runs accumulate.</td></tr></tbody></table><hr><h2 id="_7-bookmark-drill-through" tabindex="-1">7. Bookmark + drill-through <a class="header-anchor" href="#_7-bookmark-drill-through" aria-label="Permalink to &quot;7. Bookmark + drill-through&quot;">​</a></h2><p><code>View &gt; Bookmarks &gt; New Bookmark</code>. Create:</p><ul><li><strong>Compliance to Auditor:</strong> target the Auditor page, filtered by the selected <code>control_id</code>.</li><li><strong>Signals to Auditor:</strong> target the Auditor page, filtered by the selected <code>signal_id</code>.</li></ul><p><code>Insert &gt; Buttons &gt; Drill through</code>. Place a button on each source page that triggers the bookmark.</p><hr><h2 id="_8-save-as-pbit" tabindex="-1">8. Save as <code>.pbit</code> <a class="header-anchor" href="#_8-save-as-pbit" aria-label="Permalink to &quot;8. Save as \`.pbit\`&quot;">​</a></h2><ol><li><code>File &gt; Export &gt; Power BI template</code>.</li><li>Save as: <code>swao-report.pbit</code></li><li>Description: &quot;SWAO single-app BI dashboard. Reads star-schema CSV bundle from <code>wsp/exports/&lt;ts&gt;/star/</code>. ADR-0026.&quot;</li><li>Move the saved file to: <code>swao/docs/templates/powerbi/swao-report.pbit</code></li><li>Commit the binary file to git (the <code>.pbit</code> is small, ~50-100 KB).</li></ol><hr><h2 id="_9-smoke-test" tabindex="-1">9. Smoke test <a class="header-anchor" href="#_9-smoke-test" aria-label="Permalink to &quot;9. Smoke test&quot;">​</a></h2><p>In a fresh PowerBI Desktop:</p><ol><li><code>File &gt; Open &gt; swao-report.pbit</code></li><li>Paste the absolute path to a different (or the same) <code>star/</code> directory when prompted.</li><li>Verify all six pages render with non-empty visuals.</li><li>Click a control row on Compliance -&gt; Auditor page should drill through with the control filtered.</li><li>Save the manual smoke-test result to <code>docs/templates/powerbi/CHANGELOG.md</code> (one line per smoke test):</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2026-05-09  swao-report.pbit  v1.0  Initial template; smoke OK against sovereign-health</span></span></code></pre></div><hr><h2 id="_10-bundle-schema-versioning" tabindex="-1">10. Bundle schema versioning <a class="header-anchor" href="#_10-bundle-schema-versioning" aria-label="Permalink to &quot;10. Bundle schema versioning&quot;">​</a></h2><p>The template carries an implicit dependency on the SWAO bundle schema version (<code>bundle_schema_version: &quot;1.0.0&quot;</code> in <code>manifest.yaml</code>). When the star-schema columns change:</p><ul><li><strong>Patch bump (1.0.0 -&gt; 1.0.1):</strong> column added, no template change needed.</li><li><strong>Minor bump (1.0.0 -&gt; 1.1.0):</strong> column added that the template should display; update the template, bump CHANGELOG.</li><li><strong>Major bump (1.0.0 -&gt; 2.0.0):</strong> column renamed or removed; old template will fail to load. Must rebuild against the new schema and publish a new <code>.pbit</code> version.</li></ul><hr><h2 id="_11-common-issues" tabindex="-1">11. Common issues <a class="header-anchor" href="#_11-common-issues" aria-label="Permalink to &quot;11. Common issues&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Cause</th><th>Fix</th></tr></thead><tbody><tr><td>&quot;Column &#39;X&#39; is not in the data&quot; on load</td><td>Schema bump removed/renamed column</td><td>Open template, refresh against current bundle, re-save</td></tr><tr><td>Numeric columns showing as text</td><td>Auto-detect missed; CSV-as-text fallback</td><td>Power Query Editor -&gt; Change Type -&gt; Decimal Number</td></tr><tr><td>Relationships show as inactive</td><td>Many-to-many ambiguity through link tables</td><td>Set link tables to single-direction filter (link side -&gt; dim side)</td></tr><tr><td><code>derivation_chain</code> column appears as one giant string</td><td>Expected; we keep as semicolon-joined text</td><td>If you want a true list, split the column in Power Query</td></tr><tr><td>Drill-through doesn&#39;t fire</td><td>Missing bookmark or wrong target page</td><td>View &gt; Bookmarks: confirm the bookmark exists and references the right page</td></tr></tbody></table><hr><h2 id="_12-reference-links" tabindex="-1">12. Reference links <a class="header-anchor" href="#_12-reference-links" aria-label="Permalink to &quot;12. Reference links&quot;">​</a></h2><ul><li>ADR-0026 (BI export format and templates)</li><li>Design 019 Â§4 (PowerBI template spec)</li><li>Design 020 (auditor view; matches the data the template reads)</li><li><code>src/exports/star.ts</code> (canonical column shape)</li><li><code>REFRESH-RUNBOOK.md</code> (operator workflow for re-running an assessment and refreshing the dashboard)</li></ul><hr><h2 id="_13-future-enhancements-backlog" tabindex="-1">13. Future enhancements (backlog) <a class="header-anchor" href="#_13-future-enhancements-backlog" aria-label="Permalink to &quot;13. Future enhancements (backlog)&quot;">​</a></h2><p>Items observed during v1.0 authoring that should land in v1.1 of the template:</p><h3 id="multi-run-timeline-per-run-filter-issue-0195" tabindex="-1">Multi-run timeline + per-run filter (issue #0195) <a class="header-anchor" href="#multi-run-timeline-per-run-filter-issue-0195" aria-label="Permalink to &quot;Multi-run timeline + per-run filter (issue #0195)&quot;">​</a></h3><p><strong>Goal:</strong> when a workspace accumulates multiple <code>swao assess</code> runs, let users compare them side-by-side or filter the dashboard to a specific run.</p><p><strong>Blockers in v1.0:</strong></p><ul><li>Each export bundle contains exactly one run. To compare across runs, the user must load multiple bundles into a single <code>.pbix</code> (currently a manual Append Query operation).</li><li><code>fact_signals</code>, <code>fact_controls</code>, <code>fact_findings</code>, <code>fact_risks</code>, <code>fact_assessments</code> do not carry a <code>run_id</code> foreign key today -- they are implicitly the &quot;current run&quot; of the bundle they came in. A multi-bundle merge would lose the link from a signal to its source run.</li></ul><p><strong>Proposed implementation:</strong></p><ul><li>Add <code>run_id</code> column to every fact table during export (<code>src/exports/star.ts</code>).</li><li>Bump <code>bundle_schema_version</code> to <code>1.1.0</code> (additive minor).</li><li>Add a <code>Datenschnitt</code> (Slicer) on each page bound to <code>fact_runs[finished_at]</code> (date dropdown).</li><li>Mark the slicer <strong>Synchronisieren</strong> across all pages so a selection on one page applies everywhere.</li><li>Document a &quot;Bundle-Append&quot; workflow in <code>REFRESH-RUNBOOK.md</code> for multi-run analysis.</li></ul><h3 id="three-single-purpose-dim-severity-tables-issue-0195-sub-task" tabindex="-1">Three single-purpose <code>dim_severity</code> tables (issue #0195 sub-task) <a class="header-anchor" href="#three-single-purpose-dim-severity-tables-issue-0195-sub-task" aria-label="Permalink to &quot;Three single-purpose \`dim_severity\` tables (issue #0195 sub-task)&quot;">​</a></h3><p><code>dim_severity.csv</code> currently bundles three taxonomies (severity levels, control outcomes, signal outcomes). PowerBI cannot create a *:1 relationship from any fact to it -- forces M:N.</p><p><strong>Proposed:</strong> export three dims:</p><ul><li><code>dim_severity_level</code> -- 6 rows (critical, high, medium, low, informational, positive)</li><li><code>dim_control_outcome</code> -- 5 rows (SATISFIED, PARTIAL, GAP, UNKNOWN, N_A)</li><li><code>dim_signal_outcome</code> -- 4 rows (positive, neutral, indeterminate, negative)</li></ul><p>This unblocks proper <code>*:1</code> relationships from <code>fact_signals</code> and <code>fact_controls</code> and lets visuals reference <code>dim_severity_level[rank]</code> for severity ordering.</p><h3 id="drill-through-bookmarks-deferred-from-v1-0" tabindex="-1">Drill-through bookmarks (deferred from v1.0) <a class="header-anchor" href="#drill-through-bookmarks-deferred-from-v1-0" aria-label="Permalink to &quot;Drill-through bookmarks (deferred from v1.0)&quot;">​</a></h3><p>Bookmarks for &quot;Compliance -&gt; Auditor (filtered by control_id)&quot; and &quot;Signals -&gt; Auditor (filtered by signal_id)&quot; are described in Â§7 but were skipped from the v1.0 build to ship the smoke test. Add in v1.1.</p><h3 id="backfilled-fact-controls-auditor-columns-depends-on-0194" tabindex="-1">Backfilled <code>fact_controls</code> auditor columns (depends on #0194) <a class="header-anchor" href="#backfilled-fact-controls-auditor-columns-depends-on-0194" aria-label="Permalink to &quot;Backfilled \`fact_controls\` auditor columns (depends on #0194)&quot;">​</a></h3><p><code>fact_controls.{rationale, signal_refs, evidence_ids, assessor, assessed_at, remediation}</code> are unpopulated in v0.10 fixtures and only become useful when the auditor enricher (#0194 / WSP v0.11) backfills them. Once that ships, the Page 5 (Auditor) table should switch from <code>fact_assessments</code> back to <code>fact_controls</code> for the richer view.</p>`,231)])])}const g=t(i,[["render",d]]);export{u as __pageData,g as default};
